import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js'; // Agregamos el .js al final

dayjs.extend(customParseFormat);

// Activamos el soporte para formatos de fecha personalizados
dayjs.extend(customParseFormat);

export const processLogisticsData = (datos) => {
  if (!datos || datos.length === 0) return null;

  // 1. KPIs GLOBALES
  const total = datos.length;
  // Una pieza está "etiquetada" si tiene contenido en 'Labeling Date Printed'
  const piezasEtiquetadas = datos.filter(d => 
    d['Labeling Date Printed'] && d['Labeling Date Printed'].trim() !== ""
  ).length;

  const pendientes = total - piezasEtiquetadas;
  const eficiencia = total > 0 ? ((piezasEtiquetadas / total) * 100).toFixed(2) : "0.00";

  // 2. DATOS PARA LA GRÁFICA (Hasta las 23:00)
  const chartMap = {};
  // Creamos franjas cada 2 horas desde las 01:00 hasta las 23:00 para cubrir tus datos de madrugada
  const franjas = ["01:00", "03:00", "05:00", "07:00", "09:00", "11:00", "13:00", "15:00", "17:00", "19:00", "21:00", "23:00"];

  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  datos.forEach(row => {
    // IMPORTANTE: Definimos el formato exacto de tu CSV: "23/03/2026 02:52:05"
    const formatoCSV = "DD/MM/YYYY HH:mm:ss";

    const fArribo = row['Inbound Date Closed'];
    const fBipeo = row['Labeling Date Printed'];

    if (fArribo && fArribo.trim() !== "") {
      const fecha = dayjs(fArribo, formatoCSV);
      if (fecha.isValid()) {
        const h = fecha.format('HH:00');
        // Si la hora es impar (ej: 02:00), buscamos su franja o la redondeamos
        const hKey = Object.keys(chartMap).find(k => k === h) || 
                     (parseInt(h) > 0 ? `${(parseInt(h)-1).toString().padStart(2,'0')}:00` : "01:00");
        if (chartMap[hKey]) chartMap[hKey].arribo++;
      }
    }

    if (fBipeo && fBipeo.trim() !== "") {
      const fecha = dayjs(fBipeo, formatoCSV);
      if (fecha.isValid()) {
        const h = fecha.format('HH:00');
        const hKey = Object.keys(chartMap).find(k => k === h) || 
                     (parseInt(h) > 0 ? `${(parseInt(h)-1).toString().padStart(2,'0')}:00` : "01:00");
        if (chartMap[hKey]) chartMap[hKey].bipeo++;
      }
    }
  });

  // 3. TABLA DE ARMADO DE HU
  const tableData = franjas.slice(2).map(hora => {
    const inicio = dayjs(`2026-03-23 ${hora}`); // Usamos la fecha de tu data
    const fin = inicio.add(2, 'hour');

    const enIntervalo = datos.filter(d => {
      if (!d['Labeling Date Printed']) return false;
      const dHora = dayjs(d['Labeling Date Printed'], "DD/MM/YYYY HH:mm:ss");
      return dHora.isAfter(inicio) || dHora.isSame(inicio);
    });

    return {
      intervalo: `${hora} - ${fin.format('HH:00')}`,
      etiquetado: Math.max(enIntervalo.length, 1500), // Simulación de Target
      piezas: enIntervalo.length,
      usuarios: [...new Set(enIntervalo.map(d => d['Inbound User ID']))].length || 0
    };
  });

  return {
    kpis: { 
      total: total.toLocaleString(), 
      pendientes: pendientes.toLocaleString(), 
      eficiencia 
    },
    chartData: Object.values(chartMap),
    tableData
  };
};
